import android.content.Context
import android.content.SharedPreferences
import javax.inject.Inject
 
class UserLoginManager @Inject constructor(private val context : Context) {
    private lateinit var sharedPrefs: SharedPreferences
    
    init{        
        this.sharedPrefs = context.getSharedPreferences("MyApp",Context.MODE_PRIVATE);  // Create a new instance of the preference manager, use your app's name for it and set mode to private (this means data will not be shared between apps)  
    }    
     
    fun saveUserID(userId: String){        
        val editor = this.sharedPrefs.edit()  // Get an instance of SharedPreferences Editor, which is used for editing the preference settings in a convenient way (e.g., store user ID)  
         
        editor?.putString("UserID",userId)?.apply();    // Store User id as string with key "UserID"  and apply changes to shared preferences    
        
       }     
          
    fun saveAuthToken(authToken: String){            
            val editor = this.sharedPreferences?.edit()   // Get an instance of SharedPreferences Editor, which is used for editing the preference settings in a convenient way (e.g., store user ID) 
             
        if(!this::editor.isInitialized || !(authToken == "")){ return }    // Check whether editor has been initialized and auth token isn't empty  
         
            editor?.putString("Auth_token",authToken)?.apply()     // Store Auth Token as string with key “Auth-token”, apply changes to shared preferences     
        }      
          
    fun getUserID(): String? {         return this.sharedPrefs.getString("userId","")   // Get User ID by using the preference manager (default value is ""), if not found then default will be returned  */    
         
    fun getAuthToken() :String ?{      return sharedPreferences?.getString ("auth_token",null) }//Get Auth Token, If Not Found Then Return Null  
}